module RefModule(
    input clk,
    input reset,
    input up,
    input down,
    output reg [3:0] count
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            count <= 0;
        else if (up & ~down)
            count <= count + 1;
        else if (~up & down)
            count <= count - 1;
    end

endmodule
